TITLE = 'リモートワーク環境・コスト診断 | テレワーク快適度と費用を無料チェック | AppADayCreator'
DESCRIPTION = '在宅勤務・テレワークの環境と毎月のコストを7つの質問で診断。快適なリモートワーク環境構築に必要な機器・ツール・費用目安をアドバイスします。'
JS_CODE = 'const questions = [\n    {\n      id: \'frequency\',\n      text: \'リモートワークの頻度を教えてください\',\n      options: [\'週5日（フルリモート）\', \'週3〜4日\', \'週1〜2日\', \'月数回程度\', \'これから導入予定\']\n    },\n    {\n      id: \'workspace\',\n      text: \'現在の作業スペースはどこですか？\',\n      options: [\'専用の書斎・部屋がある\', \'リビング・ダイニングで作業\', \'寝室で作業\', \'カフェ・コワーキングを活用\', \'まだ環境が整っていない\']\n    },\n    {\n      id: \'equipment\',\n      text: \'PC環境の状況を教えてください\',\n      options: [\'ノートPC1台のみ（会社支給）\', \'ノートPCにモニターを接続\', \'デスクトップPC・デュアルモニター環境\', \'高スペックなゲーミングPC等がある\']\n    },\n    {\n      id: \'internet\',\n      text: \'インターネット環境はどうですか？\',\n      options: [\'光回線（安定している）\', \'光回線だが速度が不満\', \'ケーブルTV・ADSL回線\', \'スマートフォンのテザリング\', \'WiFi環境が不安定\']\n    },\n    {\n      id: \'tools\',\n      text: \'現在利用しているビジネスツールの費用は月間いくらですか？\',\n      options: [\'ほぼ無料ツールのみ（〜500円）\', \'月1,000〜3,000円程度\', \'月3,000〜10,000円程度\', \'月10,000円以上\']\n    },\n    {\n      id: \'productivity\',\n      text: \'リモートワーク中の生産性（集中度）はオフィス比較でどうですか？\',\n      options: [\'オフィスより高い（120%以上）\', \'ほぼ同じ（80〜120%）\', \'やや低い（50〜80%）\', \'かなり低い（50%未満）\']\n    },\n    {\n      id: \'issue\',\n      text: \'リモートワークで最も困っていることは何ですか？\',\n      options: [\'PC・機器が古い・不足している\', \'インターネットが遅い・不安定\', \'作業スペースが狭い・環境が悪い\', \'オンライン会議の音声・映像品質\', \'コミュニケーション・孤独感\']\n    }\n  ];\n\n  let currentStep = 0;\n  let answers = {};\n\n  function renderQuestion() {\n    const q = questions[currentStep];\n    document.getElementById(\'step-label\').textContent = `質問 ${currentStep + 1} / ${questions.length}`;\n    document.getElementById(\'progress-bar\').style.width = `${((currentStep + 1) / questions.length) * 100}%`;\n    document.getElementById(\'prev-btn\').classList.toggle(\'hidden\', currentStep === 0);\n    document.getElementById(\'next-btn\').textContent = currentStep === questions.length - 1 ? \'診断する\' : \'次へ\';\n\n    let html = `<p class="font-semibold text-gray-800 mb-4">${q.text}</p><div class="space-y-2">`;\n    q.options.forEach(opt => {\n      const checked = answers[q.id] === opt ? \'checked\' : \'\';\n      html += `<label class="flex items-center gap-3 p-3 border border-gray-200 rounded-xl cursor-pointer hover:border-violet-400 transition has-[:checked]:border-violet-500 has-[:checked]:bg-violet-50">\n        <input type="radio" name="${q.id}" value="${opt}" ${checked} class="accent-violet-600"> <span class="text-sm">${opt}</span>\n      </label>`;\n    });\n    html += \'</div>\';\n    document.getElementById(\'question-area\').innerHTML = html;\n  }\n\n  function saveAnswer() {\n    const el = document.querySelector(`input[name="${questions[currentStep].id}"]:checked`);\n    if (!el) { alert(\'選択してください\'); return false; }\n    answers[questions[currentStep].id] = el.value;\n    return true;\n  }\n\n  function nextStep() {\n    if (!saveAnswer()) return;\n    if (currentStep < questions.length - 1) { currentStep++; renderQuestion(); }\n    else showResult();\n  }\n\n  function prevStep() {\n    if (currentStep > 0) { currentStep--; renderQuestion(); }\n  }\n\n  function calcScore() {\n    let score = 50;\n    if (answers.workspace === \'専用の書斎・部屋がある\') score += 20;\n    else if (answers.workspace === \'リビング・ダイニングで作業\') score += 5;\n    else if (answers.workspace === \'まだ環境が整っていない\') score -= 15;\n\n    if (answers.equipment.includes(\'デスクトップ\') || answers.equipment.includes(\'高スペック\')) score += 20;\n    else if (answers.equipment.includes(\'デュアルモニター\') || answers.equipment.includes(\'モニターを接続\')) score += 10;\n\n    if (answers.internet === \'光回線（安定している）\') score += 15;\n    else if (answers.internet === \'スマートフォンのテザリング\' || answers.internet.includes(\'不安定\')) score -= 15;\n\n    if (answers.productivity.includes(\'高い\')) score += 10;\n    else if (answers.productivity.includes(\'かなり低い\')) score -= 20;\n\n    return Math.max(0, Math.min(100, score));\n  }\n\n  function showResult() {\n    document.getElementById(\'quiz-section\').classList.add(\'hidden\');\n    document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n    const score = calcScore();\n    const level = score >= 80 ? \'優秀\' : score >= 60 ? \'標準\' : score >= 40 ? \'要改善\' : \'要整備\';\n    const levelColor = score >= 80 ? \'text-green-600\' : score >= 60 ? \'text-blue-600\' : score >= 40 ? \'text-amber-600\''
